"use client";
import { useEffect } from "react";

export default function PrintMode() {
  useEffect(() => {
    const cls = "print-mode";
    document.body.classList.add(cls);
    return () => {
      document.body.classList.remove(cls);
    };
  }, []);
  return null;
}

