import { projects } from "@/content/projects";

export const metadata: Metadata = {
  title: "Projects",
  description: "Index of Michael Quintin's projects.",
};

export default function ProjectsPage() {
  return (
    <Container size="base">
      <h1>Projects</h1>
      <div className="stack">
        {projects.map((p) => (
          <Card
            key={p.slug}
            href={`/projects/${p.slug}`}
            title={p.title}
            meta={`${p.code} · ${p.status}`}
          >
            {p.tagline}
          </Card>
        ))}
      </div>
    </Container>
  );
}

