  --bg-2:        var(--bg-raise);
  --bg-3:        var(--line);
  --rule:        var(--line);
  --fg-hi:       var(--fg);
  --fg-dim:      var(--fg-mute);
  --accent-dim:  var(--accent-mute);
  --danger:      var(--error);

