const fs = require('fs');
// Create a minimal 16x16 32-bit ICO
const W = 16, H = 16;
// Compute parts
const bmpHeaderSize = 40;
const pixelDataSize = W * H * 4;
const andMaskSize = (Math.ceil(W/32)*4) * H; // 4 bytes per row * H = 64
const imageSize = bmpHeaderSize + pixelDataSize + andMaskSize;
const fileSize = 6 + 16 + imageSize;
const buf = Buffer.alloc(fileSize);
let o = 0;
// ICONDIR
buf.writeUInt16LE(0, o); o+=2;
buf.writeUInt16LE(1, o); o+=2;
buf.writeUInt16LE(1, o); o+=2;
// ICONDIRENTRY
buf.writeUInt8(W, o); o+=1;
buf.writeUInt8(H, o); o+=1;
buf.writeUInt8(0, o); o+=1; // colors
buf.writeUInt8(0, o); o+=1; // reserved
buf.writeUInt16LE(1, o); o+=2; // planes
buf.writeUInt16LE(32, o); o+=2; // bpp
buf.writeUInt32LE(imageSize, o); o+=4;
buf.writeUInt32LE(22, o); o+=4; // image offset = 6+16
// BITMAPINFOHEADER
buf.writeUInt32LE(40, o); o+=4;
buf.writeInt32LE(W, o); o+=4;
buf.writeInt32LE(H*2, o); o+=4; // height = 2*H for ICO
buf.writeUInt16LE(1, o); o+=2;
buf.writeUInt16LE(32, o); o+=2;
buf.writeUInt32LE(0, o); o+=4; // BI_RGB
buf.writeUInt32LE(pixelDataSize, o); o+=4;
buf.writeInt32LE(0, o); o+=4;
buf.writeInt32LE(0, o); o+=4;
buf.writeUInt32LE(0, o); o+=4;
buf.writeUInt32LE(0, o); o+=4;
// Pixel data: bottom-up BGRA
// fill with accent color: #c9a96e -> R=0xc9 G=0xa9 B=0x6e A=0xff
for (let y=0; y<H; y++) {
  for (let x=0; x<W; x++) {
    buf.writeUInt8(0x6e, o); o+=1; // B
    buf.writeUInt8(0xa9, o); o+=1; // G
    buf.writeUInt8(0xc9, o); o+=1; // R
    buf.writeUInt8(0xff, o); o+=1; // A
  }
}
// AND mask (all zeros = opaque)
o += andMaskSize;
fs.writeFileSync('src/app/favicon.ico', buf);
console.log('wrote', fileSize, 'bytes');
